require 'rails/application'

Rails.application.routes.draw do
  # Routes for workflows generated by controller generator
  resources :workflows, only: [:index, :new, :create, :show, :destroy]
  # End routes for workflows

  # Routes for waitlists generated by controller generator
  # Waitlist for launch notifications
  post 'api/waitlist', to: 'waitlist#create', as: :api_waitlist
  resources :waitlists, only: [:index, :new, :create, :show, :edit, :update, :destroy]
  # End routes for waitlists

  # Postforme OAuth callback
  get 'auth/postforme/callback', to: 'social_account_connections#oauth_callback'
  post 'auth/postforme/callback', to: 'social_account_connections#oauth_callback'
  
  # Pricing page route
  get 'subscription', to: 'pricing#index', as: :subscription
  resources :pricing, only: [] do
    collection { get :index }
  end
  # End routes for pricings

  # Routes for subscriptions (create only)
  resources :subscriptions, only: [:create]
  # End routes for subscriptions

  # Promo codes validation
  post 'api/promo_codes/validate', to: 'api/promo_codes#validate', as: :validate_promo_code
  # End routes for promo_codes

  # Routes for purchases generated by controller generator
  resources :purchases, only: [:create]
  # End routes for purchases

  resources :payments, only: [] do
    member do
      get :pay
      post :pay
      get :success
      get :failure
    end
  end
  post '/webhooks/stripe', to: 'payments#webhook'
  # Health check endpoint for Railway
  get "up" => "rails/health#show", as: :rails_health_check

  # Emergency migration fix (no auth required)
  get 'migration-fix', to: 'migration_fix#run'

  # Webhook routes for Postforme (API namespace)
  namespace :api do
    namespace :v1 do
      post 'postforme/webhook', to: 'postforme_webhooks#receive'
    end
  end

  # Webhook route for Atlas Cloud video callbacks
  post 'atlas_cloud_webhook', to: 'atlas_cloud_webhooks#video_callback'

  # Social Media Dashboard
  resources :social_media_dashboard, only: [:index] do
    post :sync_all, on: :collection
    get :available_profiles, on: :collection
    post :connect_profile, on: :collection
  end
  # Social Account Connections
  resources :social_account_connections, only: [:index] do
    post :update_api_key, on: :collection
    get :available_profiles, on: :collection
    post :connect_profile, on: :collection
