    post :share_to_social_media, on: :collection
    get :initiate_oauth, on: :collection
  end

  # Social Posts Management
  resources :social_posts do
    member do
      post 'share_now'
      get 'results'
      get 'analytics'
      get 'preview'
    end
    collection do
      get 'list'
    end
  end

  # Social Account Feeds
  get 'social_account_feeds/:account_id', to: 'social_posts#account_feed', as: :social_account_feed

  # PWA routes
  get '/manifest.json', to: 'pwa#manifest', defaults: { format: :json }
  get '/service-worker.js', to: 'pwa#service_worker', defaults: { format: :js }
  # Root path
  root "home#index"

  # ActionCable WebSocket mount
  mount ActionCable.server => '/cable'

  # Dashboard route (singular)
  get 'dashboard', to: 'dashboards#index'

  # Webhooks
  post 'webhooks/postforme', to: 'webhooks/postforme_webhooks#receive'

  # API routes
  namespace :api do
    namespace :v1 do
      # Workflow API endpoints
      post 'workflows', to: 'workflows#create'
      get 'workflows', to: 'workflows#index'
      get 'workflows/:id', to: 'workflows#show'

      # Campaign Health API endpoints
      get 'campaign_health', to: 'campaign_health#index'
      get 'campaign_health/:id', to: 'campaign_health#show'

      # Agency Dashboard API endpoints
      get 'agency/dashboard', to: 'agency#dashboard'
      get 'agency/clients/:id', to: 'agency#client'
      get 'agency/campaigns', to: 'agency#campaigns'
      get 'agency/trending', to: 'agency#trending'
      get 'agency/viral-context', to: 'agency#viral_context'
      get 'agency/costs', to: 'agency#costs'
    end
  end

  # Simple Chat API endpoint
  post '/api/v1/chat', to: 'chat#create'
  post '/api/v1/transcribe', to: 'chat#transcribe'
  post '/api/v1/speak', to: 'chat#speak'

  # Otto-Pilot AI Chat
  namespace :api do
    namespace :v1 do
      post 'otto/chat', to: 'otto#chat'
      post 'voice_settings', to: 'voice_settings#create'
      post 'otto/execute', to: 'otto#execute'
      get 'otto/draft_status', to: 'otto#draft_status'
      get 'otto/history', to: 'otto#history'
      post 'otto/clear', to: 'otto#clear'
      post 'otto/transcribe', to: 'otto#transcribe'
      post 'otto/start_onboarding', to: 'otto#start_onboarding'
      post 'otto/dismiss_onboarding', to: 'otto#dismiss_onboarding'
      get 'otto/brand_profile_status', to: 'otto#brand_profile_status'
      post 'otto/complete_onboarding', to: 'otto#complete_onboarding'
